import React, { useEffect, useState } from "react";
import GetTestimonialDetails from "src/components/services/GetTestimonialDetails";
import DataTable from "react-data-table-component";
import { customStyles } from "../../../utils/tableCustomStyles";
import { tableTestimonialConstant } from "../tableTestimonialConstant";
import { deleteModalSwal } from "src/utils/Common";
import { deleteInterest } from "src/components/services/InterestApi";

export default function testimonialList() {
  const [rowData, setRowData] = useState([]);
  const columnDefs = [
    { headerName: "Name", field: "name" },
    { headerName: "Company", field: "company" },
    { headerName: "Content", field: "content" },
    { headerName: "Rating", field: "rating" },
    { headerName: "Created At", field: "createdAt" },
  ];

  const getTestimonialList = async () => {
    let response = await GetTestimonialDetails.getAllTestimonialList();
    if(response?.code === 200) {
      setRowData(response?.results);
    }
  };

  const handleDelete = async (id) => {
    const data = await deleteInterest(id);
    if (data?.code === 200) {
      getTestimonialList();
    }
}

  const handleConfirmModal = (id) => {
      const handleConfirm = async () => {
          const swalval = await MySwal.fire(deleteModalSwal);
          if (swalval && swalval.value === true) {
              handleDelete(id)
          }
      };
      handleConfirm();
  };

  useEffect(() => {
    getTestimonialList();
  }, []);

  return (
    <div className='row'>
        <div className="col2Large">
            <DataTable
                title="Testimonial"
                columns={tableTestimonialConstant(getTestimonialList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                //actions={this.actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
    </div>
  );
}
